<?php use Illuminate\Support\Facades\Route;use App\Http\Controllers\{DashboardController,AssetController,WorkOrderController,PreventiveMaintenanceController,UserController,ReportController,SettingsController,ProfileController};
Route::get('/',fn()=>redirect('/dashboard'));Route::middleware('web')->group(function(){Route::get('/login',fn()=>view('auth.login'))->name('login');Route::post('/login',fn()=>redirect('/dashboard'));Route::get('/register',fn()=>view('auth.register'))->name('register');});
Route::middleware('web')->group(function(){Route::get('/dashboard',[DashboardController::class,'index'])->name('dashboard');Route::resource('assets',AssetController::class);Route::resource('work-orders',WorkOrderController::class);Route::resource('preventive-maintenance',PreventiveMaintenanceController::class)->only(['index','show']);Route::resource('users',UserController::class)->only(['index','show']);Route::get('reports',[ReportController::class,'index'])->name('reports.index');Route::get('settings',[SettingsController::class,'index'])->name('settings.index');Route::get('profile',[ProfileController::class,'edit'])->name('profile.edit');});
